  #price: number;

  constructor(id: string, title: string, price: number) {
    this.#id = id;
    this.#title = title;
    this.#price = price;
  }
}

class Money {
  readonly amount: number;
  readonly currency: string;

  private constructor(amount: number, currency: string) {
    if (amount < 0) throw new Error('Amount cannot be negative');
    if (currency.length < 3) throw new Error('Currency must have at least 3 characters');
    this.amount = amount;
    this.currency = currency;
  }

  static create(params: { amount: number; currency: string }): Money {
    return new Money(params.amount, params.currency);
  }

  isEqualTo(other: Money): boolean {
    return this.amount === other.amount && this.currency === other.currency;
  }

  isGreaterThan(other: Money): boolean {
    if (this.currency !== other.currency) throw new Error('Different currencies');
    return this.amount > other.amount;
  }
}
